create extension if not exists pgcrypto;
create or replace function public.set_updated_at() returns trigger language plpgsql as $$ begin new.updated_at=now(); return new; end $$;

create table public.communities(id uuid primary key default gen_random_uuid(),name text not null,slug text not null unique,category text not null,short_description text not null,description text not null,region text not null,tags text[] not null default '{}',meeting_type text not null check(meeting_type in('regular','one-time')),participation_type text not null check(participation_type in('offline','online')),fee_type text not null check(fee_type in('free','paid')),fee integer,status text not null check(status in('recruiting','closed','upcoming')),thumbnail_url text not null,next_meeting_at timestamptz,capacity integer,current_members integer,is_new boolean not null default false,is_featured boolean not null default false,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.schedules(id uuid primary key default gen_random_uuid(),community_id uuid references public.communities(id) on delete cascade,community_name text not null,title text not null,date date not null,start_time time not null,end_time time,location text not null,description text,capacity integer check(capacity is null or capacity>0),status text not null check(status in('upcoming','completed','cancelled')),created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.checklist_groups(id uuid primary key default gen_random_uuid(),community_id uuid references public.communities(id) on delete cascade,title text not null,display_order integer not null default 0,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.checklist_items(id uuid primary key default gen_random_uuid(),group_id uuid not null references public.checklist_groups(id) on delete cascade,title text not null,completed boolean not null default false,due_date date,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.community_applications(id uuid primary key default gen_random_uuid(),community_id uuid references public.communities(id) on delete cascade,community_name text not null,applicant_name text not null,applied_at date not null default current_date,introduction text not null,motivation text not null,status text not null check(status in('pending','approved','rejected')),operator_memo text,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create trigger communities_updated before update on public.communities for each row execute function public.set_updated_at();
create trigger schedules_updated before update on public.schedules for each row execute function public.set_updated_at();
create trigger checklist_groups_updated before update on public.checklist_groups for each row execute function public.set_updated_at();
create trigger checklist_items_updated before update on public.checklist_items for each row execute function public.set_updated_at();
create trigger applications_updated before update on public.community_applications for each row execute function public.set_updated_at();
alter table public.communities enable row level security;alter table public.schedules enable row level security;alter table public.checklist_groups enable row level security;alter table public.checklist_items enable row level security;alter table public.community_applications enable row level security;
create policy "public read communities" on public.communities for select to anon using(true);
create policy "demo schedules crud" on public.schedules for all to anon using(true) with check(true);
create policy "demo checklist groups crud" on public.checklist_groups for all to anon using(true) with check(true);
create policy "demo checklist items crud" on public.checklist_items for all to anon using(true) with check(true);
create policy "demo applications crud" on public.community_applications for all to anon using(true) with check(true);
grant select on public.communities to anon;grant select,insert,update,delete on public.schedules,public.checklist_groups,public.checklist_items,public.community_applications to anon;grant all on all tables in schema public to service_role;
create index communities_slug_idx on public.communities(slug);create index communities_region_idx on public.communities(region);create index schedules_date_idx on public.schedules(date);create index applications_status_idx on public.community_applications(status);
